var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"하아...... 하아...... 나 살아 있나......?","JPN":"はぁ……はぁ……私、生きてるのか……？","ENG":"Huff... Huff... Am I still alive?","TWN":"哈啊...哈啊..我活下來了嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"역시 수라장을 넘어 온 숱한 경험이...... 질긴 목숨을 잇게 해 주는군......","JPN":"やはり修羅場をくぐり抜けてきた経験が……\\n命を繋いでくれるな……","ENG":"My experience of surviving battlefield after battlefield has saved me once again.","TWN":"不愧是通過無數修羅場後累積的豐富經驗…保住了我們一條命..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"시엔 양이 넘었던 수라장은 기껏해야 보충 수업 정도 아니었습니까?","JPN":"シエンさんが経験した修羅場といえば、\\nせいぜい補講ぐらいじゃないですか？","ENG":"Battlefields? You mean supplementary lessons.","TWN":"小西恩妳通過的修羅場頂多只有留校輔導這種東西而已吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"으앙♪ 결국 잡혀 버렸어~♪","JPN":"うわ～ん♪　結局捕まっちゃったわ～♪","ENG":"Hnnnggg! ♪ In the end, we got caught! ♪","TWN":"嗚嗚嗚♪ 最終還是被抓了~♪"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"그래도 붕붕이가 안 다쳐서 다행이야♪","JPN":"でもブンブンちゃんにキズが付かなくてよかった♪","ENG":"I'm glad Vroom is safe, though. ♪","TWN":"不過還好我的蓬蓬沒受傷♪"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"시끄럽다. 아이리. 이 다음에도 무단결석을 시도할 시엔 붕붕이를 압수하겠다.","JPN":"うるさいぞ、アイリ。\\n次に無断欠席を図ったらブンブンとやらを押収するからな。","ENG":"Silence! Irie, if you try to play hooky again, I'm seizing your Vroom!","TWN":"吵死了，艾莉。之後妳要是無故缺席，我就要沒收妳的蓬蓬。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"제지도 무시하고 교정 한복판을 스쿠터로 질주하다니...... 대체 무슨 생각이냐.","JPN":"制止を無視して校庭のど真ん中をスクーターで走るなんて……\\nいったい何を考えてるんだ？","ENG":"You ignored my warnings and drove your scooter across campus. What were you thinking?","TWN":"竟敢無視勸阻，在校園中騎摩托車……妳到底是怎麼想的？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"그게......","JPN":"だって……","ENG":"But...","TWN":"因為...."},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"여기서 붕붕이랑 달릴 수 있는 것도 오늘이 마지막인걸......","JPN":"ここでブンブンちゃんを飛ばせるのも今日で最後だもん……","ENG":"Today is the last day I can drive Vroom around this place...","TWN":"因為今天就是能在校園中騎蓬蓬的最後一天嘛……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"내일부턴 차원 함선 안에 있는 이동 학교로 옮겨야 한다며.","JPN":"明日からは次元艦船の中にある移動学校に移るんでしょ？","ENG":"Starting tomorrow, we have to study in the mobile school in the dimensional ship.","TWN":"明天我們就得搬到次元艦船中的移動學校去了啊。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그, 그건......","JPN":"そ、それは……","ENG":"W-well...","TWN":"這、這個……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"그냥 그게 너무 아쉬워서...... 그래서 그랬어.","JPN":"それがすごく残念で……つい走っちゃったの。","ENG":"I was too sad to leave this place. That's why I did it.","TWN":"人家覺得很遺憾....所以才會這麼做..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"미안......","JPN":"ごめんね……","ENG":"Sorry...","TWN":"對不起..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"그쯤 해 두지, 선도부장.","JPN":"そこまでにしとけ、風紀委員長。","ENG":"That's enough, Student Guide Leader.","TWN":"就到此為止吧，先鋒部隊長。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"그 이상 소녀를 눈물짓게 한다면! 이 파란을 부르는 전학생, 린 시엔님이 두고 보지 않겠어!","JPN":"それ以上少女を泣かせたら！\\nこの波乱を呼び込む転校生、リン・シエン様が黙っていないぞ！","ENG":"If you draw one more tear out of that girl's eyes, I, Lin Xien, the Stormy Transfer Student, will punish you!","TWN":"如果妳再讓這位少女流淚的話，引起這場風波的轉學生—林·西恩是不會坐視不管的！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>아가씨. 저희는 이만 격납고가 있는 제 12 별장으로 복귀하겠습니다.</color>","JPN":"<color=#ffd34c>お嬢様。私たちは格納庫がある第12別荘に帰還いたします。</color>","ENG":"<color=#ffd34c>My Lady, let us return to the hangar at your twelfth villa now.</color>","TWN":"<color=#ffd34c>小姐，我們回到設有機庫的第12別墅吧。</color>"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L24_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"아, 그래. 응원해 주느라 고생 많았어. 퇴근해도 좋아.","JPN":"ああ、わかった。応援ご苦労だった。もう帰っていいぞ。","ENG":"Ah, okay. Thank you for your support. You may go home now.","TWN":"啊，好的。為我加油的各位辛苦了，大家可以回去囉。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"......시엔, 입학식 때부터 본 사이에 갑자기 무슨 전학생 소리지?","JPN":"……シエン、君のことは入学式から見ているのだが転校生とはどういうことだ？","ENG":"Xien, why do you call yourself a transfer student? You've been here since your entrance ceremony.","TWN":"…西恩，從入學典禮當天起就說自己是轉學生，這到底算什麼的轉學生啊?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"그냥 재학생은 심심하잖아. 전학생이 아니면 폼이 안 난다구.","JPN":"ただの在学生じゃあつまらない。転校生とでも言わないとカッコがつかないだろ。","ENG":"Just being a student is boring. Being a transfer student, however, sounds exciting.","TWN":"只是一般學生不是很無聊嗎？只有轉學生才能引起風波啊。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"오오~ 그럼 아이리 님도 오늘부터 파랑의 전학생 할래♪","JPN":"おお～じゃあ、アイリ様も今日からパランの転校生になる♪","ENG":"Oooh, then Irie wants to be a Stony Transfer Student, too! ♪","TWN":"喔喔~那從現在開始艾莉也要當引起奔波的轉學生~♪"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"파랑이 아니라 파란이야!","JPN":"パランじゃなくて波乱だ！","ENG":"Not Stony—it's Stormy!","TWN":"不是奔波，是風波！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"그리고 전학생은 한 명으로 충분하다구.","JPN":"それに、転校生は私一人で十分だ。","ENG":"Besides, this school doesn't need two transfer students.","TWN":"還有，轉學生只要有一個就夠了！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"에이~ 그러지 말구 아이리 님도 전학생 시켜 주라~♪","JPN":"ええ～そう言わずにアイリ様にも転校生やらせてよ～♪","ENG":"Come on, let Irie be a transfer student, too! ♪","TWN":"哎呀~別這樣嘛~讓艾莉也當轉學生嘛~♪"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"어, 어쨌거나!","JPN":"と、とにかく！","ENG":"A-anyway!","TWN":"我、我說妳啊!"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"푸른 하늘과 청춘은 서로를 끌어당기는 자석과도 같은 것.","JPN":"青空と青春は互いに引き寄せあう磁石のようなもの。","ENG":"The blue sky and youth pull each other like magnets.","TWN":"藍色的天和青春就像磁鐵一樣，兩個東西是互相吸引的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"그런 자연스러운 섭리를 교칙으로 통제하려 하다니! 그야말로 반자연, 반인륜적인 억압 아닌가!","JPN":"そのような自然の摂理を校則で縛ろうとするなんて！\\nそれこそ反自然、反倫理的な抑圧ではないか！","ENG":"You can't control such a natural phenomenon in the name of school rules. That's unnatural and unethical suppression!","TWN":"但人們竟然想用校規來控制這種自然的反則！這不正是反自然，反人性的壓迫嗎!"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"오, 그런 거였어? 그렇다면 아이리가 뛰쳐나간 것도 납득이 가는 걸?","JPN":"おお、そういうことなのか？　そう言われたらアイリが飛び出したのも納得だな。","ENG":"Oh, really? That explains why Irie ran out of the school.","TWN":"哦，是這樣嗎？那艾莉跑出去也是情有可原的囉？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"와아! 듣고 보니 그런 것 같아!","JPN":"わあ！　言われてみればそんな気がする！","ENG":"Wow, I also think she's right!","TWN":"哇！聽上去好像真的是這麼一回事！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"전학생, 굉장해!","JPN":"転校生、すごいね！","ENG":"Transfer Student, you're amazing!","TWN":"轉學生，妳真厲害！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"하하......","JPN":"あはは……","ENG":"Hah hah...","TWN":"哈哈…"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"후우......","JPN":"ふう……","ENG":"*Sigh*","TWN":"唉……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그래. 솔선수범해야 할 나 역시 과실을 저질렀으니, 이번 건에 대해선 보류하겠다.","JPN":"わかった。模範を見せるべき私も過ちを犯したのだから、今回の件は保留にしよう。","ENG":"Okay, since this is also partly my mistake, I'll let it slide.","TWN":"好吧，本應以身作則的我也犯了錯，那對這次的事情我就不追究了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"진짜?","JPN":"本当に？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"고마워! 정말 고마워, 선도부장!","JPN":"ありがとう！　本当にありがとう、風紀委員長！","ENG":"Thank you! Thank you so much, Student Guide Leader!","TWN":"謝謝！真的太感謝你了，先鋒部隊長！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"이야...... 그 깐깐한 선도부장이 사정을 봐 주는 날도 오고, 의외네.","JPN":"わぁ……あの厳しい風紀委員長が\\n人の事情を聞いてくれる日がくるなんて意外ね。","ENG":"Wow! Who knew the fastidious Student Guide Leader would make an exception for someone one day?","TWN":"竟然…鐵血的先鋒部隊長也有關照我的這一天，我太意外了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"외강내유라 했던가.","JPN":"外剛内柔という言葉があるだろう。","ENG":"A soft heart under a stern exterior, as they say.","TWN":"真是刀子嘴豆腐心。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"본래 저렇게 철벽 같은 인물일수록 내면은 솜사탕처럼 부드러운 법이지.","JPN":"ああやって強そうに見える人物ほど、内面は綿あめのように柔らかいものだ。","ENG":"People who seem inaccessible like her often have a heart of gold.","TWN":"果然，外表越是像鐵壁一樣的人物，內心就越是像棉花糖柔軟啊。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"훗훗. 그나저나 또 전학생답게 잠잠하던 수면에 파문을 일으키고 말았나......","JPN":"ふふっ。また転校生らしく静かな水面に波紋を起こしてしまったか……","ENG":"Hah hah. By the way, I caused a ripple in the calm lake again, like the great transfer student I am.","TWN":"呵呵，難道又要像轉學生一樣，在平靜的水面上引起一陣波紋嗎…？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"방금 전에는 파란 아니었습니까?","JPN":"さっきは波乱だと言いませんでしたか？","ENG":"Aren't you the stormy transfer student anymore?","TWN":"剛才不就已經是一場風波了嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"그, 그게 그거 아니겠냐구.","JPN":"ど、どっちもどっちだろう。","ENG":"S-same difference.","TWN":"那、那不算吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"아카데미의 학생이라면 일관성을 지켜 주십시오.","JPN":"アカデミーの生徒なら、一貫性を保ってください。","ENG":"We students of the Academy must be consistent with all our endeavors.","TWN":"作為本校的學生，請妳說話算話。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"서기는 참 한결 같네. 학생회장이 믿는 이유가 있다니까.","JPN":"書記はほんと変わらないな。生徒会長が信頼するだけある。","ENG":"Clerk, you're always the same. There's a reason the Student President trusts you so much.","TWN":"書記就說一是一，說二是二…怪不得學生會長這麼相信你！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"학생회장님이 믿는 건 학우 전원입니다. 오해를 살 만한 발언은 삼가 주십시오.","JPN":"生徒会長が信頼しているのは学友の皆さんです。\\n誤解を招くような発言はやめてください。","ENG":"The Student President trusts everyone in school. Please avoid such misleading comments.","TWN":"學生會長是相信我們所有學生。請妳不要發表會引起誤會的言論。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"아니면 혹시 본인만 학생회장님의 신뢰를 독차지하고 싶은 겁니까?","JPN":"それとも、ひょっとして生徒会長の信頼を独り占めしたいのですか？","ENG":"Or did you say that because you want to keep her trust to yourself?","TWN":"還是說你想一個人獨佔學生會長的信任?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"윽...... 뭐든 쓸데없이 진지하긴......","JPN":"うっ……ほんと無駄に真剣だな……","ENG":"Gosh, do you always have to be so serious?","TWN":"唔…你真是，什麼都這麼計較..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"무려 유진 양과의 잡담에 성의껏 임한다고 해 주십시오.","JPN":"シロコさんとの雑談に誠意をもって付き合ってるんですよ。","ENG":"I'm only trying to chat with you to the best of my ability.","TWN":"誰來告訴我要怎麼和小劉珍說話。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"의미도 맥락도 없는 잡담으로 시간을 허비하는 것보다는 훨씬 건설적이겠죠.","JPN":"意味も脈絡もない雑談で時間を無駄にするよりは、ずっと建設的でしょうから。","ENG":"I bet talking to me is much more constructive than chatting meaninglessly with others.","TWN":"比起在沒有意義和邏輯的閒談上浪費時間，我說的話更有建設性吧。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"......넌 진짜 입만 열었다 하면 왕재수야.","JPN":"……お前はほんと、口を開けば人をムカつかせるな。","ENG":"Every time you open your mouth, you make me want to hurt you.","TWN":"……你真的是只要開口就讓人覺得你很可惡耶。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"이렇게까지 쉽게 설명해 드리는데 이해를 못하시면 저도 다른 방법이 없습니다.","JPN":"ここまでわかりやすく説明しているのに\\n理解できないとおっしゃるなら、僕には他に方法がありません。","ENG":"I've tried to make things as easy as possible for you. If you still don't understand them, then I can't help you.","TWN":"我已經解釋得已經這麼清楚了，如果妳還是無法理解的話，我也沒有辦法。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"유진 양의 학습 능력은 역시 재검증이 필요하겠군요. 더 치밀한 커리큘럼을 준비하겠습니다.","JPN":"やはりシロコさんの学習能力は再検証する必要がありそうです。\\nさらに緻密なカリキュラムを用意します。","ENG":"Eujin, clearly your learning ability needs reevaluation. I'll come up with a more meticulous curriculum for you.","TWN":"小劉珍的學習能力果然需要重新檢驗。我會幫妳準備更縝密的課程。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"아, 안 돼. 넌 보충 수업이랍시고 숙제는 대학교처럼 내 주잖아.","JPN":"や、やめろ。お前は補講と言って大学並みの宿題を出すじゃないか。","ENG":"N-no! Even university students can't do the homework you come up with.","TWN":"喔不，像補習班、大學作業那樣嗎？千萬不要。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"그렇지, 야옹아! 네가 있었지!","JPN":"そうだ、にゃんこちゃん！　お前がいたな！","ENG":"Oh right, kitty cat, I totally forgot I had you!","TWN":"沒錯…貓貓！你在這裡啊!"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"가라! 저 녀석도 선도부장처럼 헤롱헤롱하게 만들어 버려!","JPN":"行け！　あいつも風紀委員長みたいにメロメロにさせちゃえ！","ENG":"Now, go! Go turn him into mush like you did with the Student Guide Leader!","TWN":"去吧！讓那傢夥也像先鋒部隊長一樣被迷得神魂顛倒吧！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"누, 누가 헤롱헤롱했다는 거냐?","JPN":"だ、誰がメロメロになっただと？","ENG":"W-who are you calling mush?","TWN":"妳、妳說誰被迷得神魂顛倒啊！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"반응이...... 없어?","JPN":"反応が……ない？","ENG":"He's not... responding?","TWN":"咦....沒反應了?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"설마, 선 채로 죽은 건가?","JPN":"まさか、立ったまま死んだとか？","ENG":"Oh no, did he die standing?","TWN":"不會吧，難道是站著死掉了嗎?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"과연, 싸나이에게 무릎을 꿇는 것은 수치!","JPN":"男にとってひざまずくのは恥だからな！","ENG":"Of course, he's a real man who refuses to kneel!","TWN":"對男子漢大丈夫而言，妥協就是一種羞恥！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"크으! 차디찬 얼굴 뒤로 열혈남아의 기질을 감추고 있었다니, 훌륭하군!","JPN":"くう！\\nクールな顔の向こうに熱血男児の気質を隠していたとは、素晴らしい！","ENG":"Ah! He was hiding such ferociousness behind his aloof mask. How commendable!","TWN":"哼哼！在冰冷的臉龐之後竟然隱藏著熱血男兒的氣質，真是厲害！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"죽긴 누가 죽습니까? 그리고 교실은 애완동물 출입금지입니다.","JPN":"死んだって、誰がですか？　あと、教室にペットの持ち込みは禁止ですよ。","ENG":"No, I didn't. And pets are not allowed in classrooms.","TWN":"妳說誰死了？而且禁止把寵物帶進教室。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"......하지만 지금 같은 상황에선 길에 풀어 주기도 어렵겠죠. 우선 데리고 있도록 합시다.","JPN":"……しかし、今のこの状況では外に放すことも難しいでしょう。\\nひとまず保護しましょうか。","ENG":"... But the streets are too dangerous for him, too. We'll keep him with us for now.","TWN":"……但現在這種局勢，我們很難把牠丟回路邊，不然將貓交給我吧。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"어, 엇......? 교장선생님?","JPN":"え、えっ……？　校長先生？","ENG":"Err, err? Mr. Principal?","TWN":"噢什…？校長大人？！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"하하, 다들 여기 모여 있었네요.","JPN":"はは、皆さんこちらに集まっていましたか。","ENG":"Hah hah, you were all here.","TWN":"哈哈，大家都聚在這裡呢。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"교장선생님! 좋은 아침!","JPN":"校長先生！　おはよう！","ENG":"Mr. Principal! Good morning!","TWN":"校長！早上好！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"고맙군요. 아이리 양도 좋은 아침입니다.","JPN":"ありがとう、アイリさん。おはようございます。","ENG":"Thank you. Good morning to you too, Irie.","TWN":"謝謝，艾莉同學，妳也早啊。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"아이리, 교장 선생님과 하이파이브로 인사하지 말라고 했을 텐데?","JPN":"アイリ、校長先生とハイタッチで挨拶するなと言ったはずだが？","ENG":"Irie, I told you not to hi-five the Mr. Principal.","TWN":"艾莉，妳該不會是用擊掌來和校長打招呼吧?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"크흠! 오늘도 어둠의 흑막 같은 분위기가 물씬 풍기는군, 보스!","JPN":"ごほん！　今日も闇の黒幕のようなオーラが漂っているな、ボス！","ENG":"Hmm, you look as sinister as usual, like the boss of the darkness that you are.","TWN":"嗯！你今天也充滿了黑暗的氣息呢，老師！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"보스가 아니라 교장 선생님입니다. 호칭에 주의하십시오.","JPN":"ボスじゃなくて校長先生です。呼び方には注意してください。","ENG":"Not a boss; Mr. Principal. Please address him properly.","TWN":"不是老師，是校長。請妳注意稱呼。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"하하, 괜찮습니다. 모두들 한결 같이 기운이 넘쳐 보여서 저도 기분이 좋군요.","JPN":"はは、大丈夫ですよ。みんながいつもどおり元気そうで、私も嬉しいです。","ENG":"Hah hah, it’s okay. I'm glad you all look so energetic today.","TWN":"哈哈，沒關係。看到大家這麼有精神，我也很高興。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"그런데 왠 일로 여기까지 내려오셨어요, 선생님?","JPN":"ところで先生、ここにはどんな用事で来られたんですか？","ENG":"By the way, what brings you all the way down here, Mr. Principal?","TWN":"不過您為什麼會來這裡呢，老師？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"건강 때문에 평소엔 바람도 잘 안 쐬셨잖아요. 아직 날씨도 쌀쌀한데......","JPN":"健康のために、普段はあまり外にもでないでしょう？\\nまだ肌寒いですし……","ENG":"I thought you shouldn't be exposed to cold air because of your health. It's still chilly outside.","TWN":"因為您身體的關係，您平常不能吹風啊，最近天氣又很冷..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"그래요. 하지만 오늘은 특별한 날이라서요.","JPN":"そうですね。でも今日は特別な日なんです。","ENG":"Yes, but today's a special day.","TWN":"沒錯，不過今天是特別的日子。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"다들 알고 계시겠지만, 이 교사로 등교하는 것도 오늘이 마지막입니다.","JPN":"みんなも知ってのとおり、この校舎に登校するのは今日で最後ですからね。","ENG":"As you know, today is our last day in this school.","TWN":"大家應該都知道了吧，今天也是我最後一次以老師的身份到學校來了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"통신문에 적힌 대로, 내일부턴 차원 함선 내부에 마련된 이동 교실에서 생활하게 될 거에요.","JPN":"お便りにも書いたとおり、明日からは次元艦船の内部に作られた移動教室で勉強することになります。","ENG":"As it's written in the latest newsletter, you will all be studying in the mobile classroom inside the dimensional ship, starting tomorrow.","TWN":"正如通知上所說的，從明天開始，我們要在次元艦船內部的移動教室裡度過了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"어떻게든 이 교정을 지켜내고 싶었지만, 침식 현상의 확산이 너무 빨라 더 이상은 어렵게 됐습니다.","JPN":"何とかこの学校を守りたかったのですが、\\n侵食現象の広がりが速すぎて限界を迎えました。","ENG":"I wanted to protect this campus, but the Counterside Effect has been spreading too quickly.","TWN":"無論我們多麼想保住這個校園，但侵蝕現象的擴散太快，很難再堅持下去。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"미안합니다. 노력해 봤지만 지금은 이게 최선인 것 같군요.","JPN":"申し訳ありません。\\n努力しましたがここまでのようです。","ENG":"I'm sorry. This is the best I can do for now.","TWN":"對不起，雖然我已經盡力了，但這是目前最好的方法了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"가르치는 이와 배우는 사람이 있다면 내게는 그곳이 학교다. 상관없어.","JPN":"教える者と学ぶ者さえいればそこが学校だ。場所はどこでも構わない。","ENG":"I don't care where I learn, so long as I can learn.","TWN":"但只要有人願意教，有人願意學，那裡就是一間學校，所以不需要在意。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"저희는 평범한 학생이 아닌 소명을 짊어진 카운터들. 그런 일로 어리광 피울 순 없습니다.","JPN":"僕たちは平凡な生徒ではなく、使命を背負ったカウンターです。\\nそのようなことで甘えることはできません。","ENG":"We're not ordinary students, but Counters on a mission. We won't complain about such trivial matters.","TWN":"我們不是普通的學生，而是背負著使命的制裁者，不能因為這種事撒嬌抱怨。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"건물 같은 게 뭐 중요하겠어. 운동장이면 몰라도.","JPN":"建物は重要じゃない。グラウンドならともかくな。","ENG":"Buildings don't matter... Maybe except for the stadium.","TWN":"建築物什麼的，又有什麼重要的呢？我甚至不在乎操場呢。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"다들 이해해 줘서 고맙습니다.","JPN":"皆さん、理解してくれてありがとう。","ENG":"Everyone, thank you for your understanding.","TWN":"謝謝大家願意理解。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"앞으로 얼마나 이 학교를 이끌어나갈 수 있을지 모르겠지만......","JPN":"いつまでこの学校を導いていけるかわかりませんが……","ENG":"I don't know how longer I can keep the school going,","TWN":"我不知道今後能帶領這所學校的大家走多遠……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"저 역시 마지막까지 여러분이 즐거운 학창생활을 보낼 수 있도록 최선을 다하겠습니다.","JPN":"最後まで皆さんが楽しい学生生活を送れるように最善を尽くします。","ENG":"but I'll do my best to help you enjoy your student life.","TWN":"但我一定會努力到最後，讓大家過上快樂平穩的學生生活。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"그런데 우리가 탈 차원 함선은 어디로 가는 거야?","JPN":"で、俺たちが乗る次元艦船はどこに向かうんだ？","ENG":"By the way, where will our dimensional ship be headed to?","TWN":"但是我們乘坐的次元艦船要開到哪裡啊？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"아니, 뭐, 고양이를 기를 수 있는 데인지 궁금해서 그러는 건 아닌데...... 함선은 중요한 무기니까......","JPN":"いや、猫が飼える環境なのかを気にしているわけじゃなくて……\\n艦船は大事な武器だから……","ENG":"Well, I'm not asking because I want to know if I can keep this cat; I'm asking because ships are important weapons...","TWN":"沒有啦，我不是好奇那裡是不是可以養貓...因為艦船是重要的武器嘛..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"다, 다들 왜 그렇게 봐?","JPN":"み、みんなどうしたんだ？","ENG":"Wh-why is everyone looking at me like that?","TWN":"大、大家幹嘛這樣看我？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"역시 내가 또 말 실수한 건가?","JPN":"俺また失言でもしたのか？","ENG":"What did I say wrong this time?","TWN":"我果然又說錯什麼話了嗎?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"아니, 방금 질문은 아주 좋았다.","JPN":"いや、すごくいい質問だった。","ENG":"No. I liked that question.","TWN":"不，剛才的提問非常好。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"저도 같은 생각입니다. 유진 양의 학습 능력을 재검증할 필요는 없겠군요.","JPN":"僕も同感です。シロコさんの学習能力を再検証する必要はなさそうですね。","ENG":"So did I. Eujin, your learning ability doesn't need reevaluation.","TWN":"我也這麼認為，看來不需要再驗證小劉珍的學習能力了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"어...... 엥?","JPN":"あ……え？","ENG":"Err... What?","TWN":"呃……咦?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"하하. 궁금하실 만도 하죠.","JPN":"はは。気になって当然です。","ENG":"Hah hah. Of course, you're curious.","TWN":"哈哈，妳當然好奇。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"내일 새로 완성될 차원함선에 탑승하는 순간부터 여러분은 카운터 아카데미의 졸업반이자 견습 전투원으로 대우받게 될 겁니다.","JPN":"明日完成する次元艦船に搭乗した瞬間から、\\n皆さんはカウンターアカデミーの卒業組であり、見習い戦闘員として扱われることになります。","ENG":"The moment you get on the new dimensional ship that will begin operating tomorrow, you'll become senior students at the Academy, and also training combatants.","TWN":"明天，在登上新造次元艦船的那一刻起，妳們就會成為制裁者學院的畢業生，接受見習戰鬥員的待遇。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"물론, 바로 격전지에 파견되지는 않을 거에요.","JPN":"もちろん、すぐ激戦地に派遣されることはありません。","ENG":"Of course, that doesn't mean you'll be fighting out on the battlefield right away.","TWN":"當然，大家不會馬上被派遣到前線。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"우리들의 첫 번째 임무는 바로 구출작전.","JPN":"私たちの初めての任務は救出作戦です。","ENG":"Our first mission is a rescue mission.","TWN":"我們的首要任務就是營救作戰。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"지난번, 제 4종 침식체가 학교를 습격했을 때 사라진 학생회장을 구출하는 겁니다.","JPN":"以前、第4種侵食体が学校を襲撃した時に\\n行方不明になった生徒会長を救出するのです。","ENG":"We'll rescue the Student President who disappeared when the Category 4 C.O. attacked the Academy the last time.","TWN":"例如：上次4類侵蝕體突襲學校時，要救出當時因此消失的學生會長。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"그게 정말입니까? 하지만 학생회장은 그때 분명......","JPN":"それは本当ですか？　しかし、あの時生徒会長は確か……","ENG":"Really? But the Student President...","TWN":"學生會長的事情是真的嗎？不過，學生會長當時明明……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"그래요. 우리를 지키는 대신 침식체와 함께 양자터널로 빨려 들어갔죠.","JPN":"はい。私たちを守ろうと侵食体と共に量子トンネルに吸い込まれました。","ENG":"Yes, she saved us and got sucked into that quantum tunnel along with the C.O.'s.","TWN":"是的，當時她為了保護我們，和侵蝕體一起被吸進了量子隧道。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 전투훈련 고문이신 힐데 교감님께서 차원 흔적을 추적한 끝에, 특정 고심도 좌표에서 학생회장과 동일한 파형의 CRF를 발견하셨다고 합니다.","JPN":"しかし、戦闘訓練顧問のヒルデ教頭が次元痕跡を追跡した結果、\\nある高深度座標から生徒会長と同じ波形のCRFを発見したそうです。","ENG":"But our Combat Training Advisor and Vice-principal Hilde followed their dimensional traces and detected the same CRF as the Student President's on certain coordinates at great depth.","TWN":"但戰鬥訓練顧問希爾德在追蹤空間軌跡時，發現在次元邊界特定的中心座標上，出現與學生會長相同的波形的CRF。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"호오, 부두목이......?","JPN":"ほう、アンダーボスが……？","ENG":"Oooh, the Deputy Boss has?","TWN":"哦，也就是說她……?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"미나를 찾아냈다고요? 정말이죠?!","JPN":"ミナを見つけたんですか？　本当ですね！？","ENG":"You've found Mina? Are you serious?","TWN":"找到米娜了嗎? 真的嗎？！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"네. 실종으로부터 꽤 시간이 지나긴 했지만, 학생회장이라면......","JPN":"ええ。失踪してからかなり時間が経ってしまいましたが、生徒会長なら……","ENG":"Yes. It's been a while since she disappeared, but the Student President...","TWN":"是的，雖然從失蹤開始已經過了很長一段時間，但學生會長……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"미나 양이라면 반드시 살아 있을 거라고, 전 믿고 있습니다.","JPN":"ミナさんなら必ず生きていると、私は信じています。","ENG":"Mina is strong enough to be alive, or so I believe.","TWN":"我相信米娜同學一定會活著的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"물론. 학생회장은 반드시 살아 있을 거다.","JPN":"もちろんだ。生徒会長は絶対に生きている。","ENG":"Definitely. The Student President is definitely alive.","TWN":"那當然，學生會長一定還活著。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"그럼 이럴 때가 아니잖아! 당장 출발해야 하는 거 아냐?","JPN":"だったらこうしてる場合じゃないだろう！\\n今すぐ出発しないとダメじゃないか？","ENG":"Then, what are we still doing here? Shouldn't we take off already?","TWN":"現在就馬上出發吧！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"다들 학생회장을 생각해 줘서 고맙군요.","JPN":"みんな生徒会長のことを思ってくれるなんて、ありがたいですね。","ENG":"Everyone, I'm glad that you all care so much about the Student President.","TWN":"謝謝大家這麼惦念學生會長。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 너무 서두르면 일을 그르치게 됩니다. 지금은 차원계면이 불안정해서 다이브하기엔 몹시 위험한 상태니까요.","JPN":"だからといって、急ぎ過ぎてはいけません。\\n今は次元界面が不安定なので、ダイブするには大変危険な状態なのです。","ENG":"But haste makes waste. Right now, the dimension surface is too unstable to be dived into.","TWN":"但我們如果操之過急，反而會把事情搞砸。因為現在次元邊界還不穩定，躍入是非常危險的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"너무 조급해하지 말고 여유를 가집시다.","JPN":"焦らずに余裕を持ちましょう。","ENG":"Let's try to not be too impatient.","TWN":"所以大家不要急，先放鬆一下。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"게다가 이번에 학교를 떠나면, 이렇게 푸른 하늘 아래 꽃이 피는 모습도 당분간 보기 어려울 거에요.","JPN":"それに校舎を離れたら、当分は青空の下に花が咲いている姿も見られなくなるでしょう。","ENG":"Besides, once we leave the school, we won't be able to see this blue sky or flowers for a long time.","TWN":"況且這次我們離開學校後，會有一段時間很難再看到藍天下花開的樣子。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"그러니 오늘만큼은 수업을 쉬기로 하죠.","JPN":"だから、今日くらいは授業をお休みしましょうか。","ENG":"So, why don't we skip class today and enjoy them?","TWN":"那今天就放假一天吧。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"수업을 안 해? 정말?!","JPN":"授業をしない？　本当！？","ENG":"We can skip class? Really?","TWN":"不上課嗎？真的嗎？！！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"좋았어! 그럼 좀 더 달려 보실까? 아이리님 나가신다!!","JPN":"よし！　じゃあもっと走ろうかな！　アイリ様が行くよぉ！！","ENG":"Alright! I'm going to drive my scooter again! Here goes Irie!","TWN":"太棒了！那我再去飆一下蓬蓬好了♪艾莉出發囉！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"아, 잠시만. 그러기 전에......","JPN":"あ、待ってください。その前に……","ENG":"Ah, wait. Before we do...","TWN":"啊，等一下。在這之前…"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"서윤 양. 내가 부탁한 건 어떻게 됐나요?","JPN":"アオイ・シズカさん。私が頼んだものはどうなりましたか？","ENG":"Seo Yoon, what happened to what I asked you?","TWN":"徐芸同學，我拜託妳的事怎麼樣了？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"네. 오늘 아침부터 학생들과 학교의 모습을 모두 촬영해 뒀어요.","JPN":"はい。今朝から生徒たちと学校の様子をすべて撮影しておきました。","ENG":"Yes, I've been filming the students and the school since this morning.","TWN":"嗯，差不多了，我從早上就把同學和校園樣子全部拍下來了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"좋아요. 그럼 이제 마무리만 남았군요.","JPN":"いいですね。残りはこれだけですか。","ENG":"Good. Now, we just need a proper ending.","TWN":"非常好，那現在只剩最後的收尾了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"각자 자유시간을 갖기 전에, 다들 한자리에 모여 보도록 할까요?","JPN":"各自、自由行動をする前に一か所に集まってください！","ENG":"Before everyone goes off to enjoy their free time, shall we gather around for one last time?","TWN":"在自由活動之前，大家先這邊集合一下吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"참전 전의 사진 촬영이군요. 알겠습니다.","JPN":"参戦前の写真撮影ですね。わかりました。","ENG":"You want to take a photo with everyone before the war. Understood.","TWN":"上戰場前的大合照嗎，好的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"졸업사진인가...... 이렇게 갑작스레 찍게 될 줄은 몰랐는데.","JPN":"卒業写真か……\\nこんな風にいきなり撮ることになるとは思わなかったな。","ENG":"A graduation photo... I didn't know it'd be so sudden.","TWN":"算是畢業照嗎… 沒想到會拍得這麼突然。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"이번에 찍은 것들은 모두 타임캡슐에 봉인해 두겠습니다.","JPN":"今日撮ったものはすべてタイムカプセルに封印しておきます。","ENG":"I'll put all the videos and photos in a time capsule.","TWN":"這次拍的東西，我都把它封存在時光膠囊裡。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"학생회장을 구출하고 나면, 함께 열어 보기로 하죠.","JPN":"生徒会長の救出が終わったら、みんなで開けることにしましょう。","ENG":"We can open it together after we save the Student President.","TWN":"等救出學生會長後，我們一起打開看看吧。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"그거 좋은 생각이네요!","JPN":"いいですね！","ENG":"That's a good idea!","TWN":"這真是個好主意！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"대신 우리끼리만 찍으면 미안하니까, 학생회장에게 보내는 인사 영상도 함께 찍어 보죠.","JPN":"でも、私たちだけだと申し訳ないので、\\n生徒会長に送る挨拶の動画も一緒に撮りましょう。","ENG":"Since the Student President can't take a photo with us today, how about we record a video message for her?","TWN":"但就只有我們拍的話太對不起學生會長了，不如我們也拍個問候學生會長的影片吧。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"헤헤, 그거 보여주면 감동해서 울어 버리는 거 아냐?","JPN":"ヘヘ、それ見せたら感動して泣いちゃうんじゃないか？","ENG":"Heh heh. She might cry if she sees it.","TWN":"嘿嘿，要是她看了那段影片肯定會感動到哭吧。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"좋은 생각이군요.","JPN":"いい考えですね。","ENG":"That's a good idea.","TWN":"真是好主意。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"그럼 다들 사진을 찍어 보죠. 평소처럼 자연스러운 모습이면 됩니다.","JPN":"では撮りましょうか。普段どおりの自然な姿で構いませんよ。","ENG":"Now, everyone. Let's take a photo. I want everyone to look natural.","TWN":"在那之後大家就來拍照吧，就像平時那樣，自然一點就行了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"평소의 자연스러운 모습이라...... 그렇다면 첫 테마는 등굣길이 좋겠군요.","JPN":"普段どおりの自然な姿か……それなら、最初のテーマは登校がいいですね。","ENG":"You want everyone to look natural. Then, we suggest we take our first photo on the road to school.","TWN":"平時的樣子啊...那麼第一個主題就是上學囉。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"오~ 아이리 님도 대찬성! 마지막 등교, 신나게 뛰어올 테야! ","JPN":"おお～アイリ様も大賛成！　最後の登校、楽しく走っちゃうぞ！ ","ENG":"Oooh, Irie seconds that! Irie wants to come running to school for one last time! ","TWN":"噢~ 艾莉超級贊成！最後一天上學，我興奮到跳起來♪"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"등굣길도 나쁘지 않군. 교실 안에선 벚꽃이 잘 안 보이니까.","JPN":"通学路も悪くないな。教室の中だと桜がよく見えないから。","ENG":"That's not a bad idea. We can't see the cherry blossoms from the inside of our classrooms.","TWN":"上學的路也很漂亮啊，雖然在教室裡看太不清楚外面的櫻花。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"음? 그런데 교장 선생님께선 오시지 않는 겁니까?","JPN":"あれ？　校長先生は入らないんですか？","ENG":"Mm? Mr. Principal, aren't you coming with us?","TWN":"咦？話說回來，校長您不過來嗎?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"네, 좋은 장면을 놓치지 않으려면 누군가는 사진을 찍어 줘야 하는 법이니까요.","JPN":"ええ。いい瞬間を逃さないためには、誰かがシャッターを押さないといけませんからね。","ENG":"I am. Someone has to take a photo of you and make sure you all look nice.","TWN":"是啊，如果要拍出好的畫面，一定要有誰去按快門才行。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"음? 어디서 터지는 소리가......?","JPN":"ん？　どこかで爆発する音が……？","ENG":"Mm? What are these popping noises?","TWN":"嗯？這是從哪裡發出的聲音？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"이건...... 꽃잎이잖아?","JPN":"これは……花びら？","ENG":"These... They're petals.","TWN":"這...不是櫻花花瓣嗎?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"바람도 안 부는데 어디서 날라오는 거지?","JPN":"風も吹いてないのに、どこから飛んできたの？","ENG":"It's not windy. Where are they coming from?","TWN":"明明沒有風啊，是從哪裡飛來的?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"아이리 님이 준비해 뒀던 비장의 트랩이란 말씀♪","JPN":"アイリ様が用意した、とっておきのトラップだよ♪","ENG":"From Irie's special traps! ♪","TWN":"是艾莉準備的盛大陷阱啦♪"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"이 전학생이 소매 걷고 도와 줬지. 훗훗훗.","JPN":"この転校生が一肌脱いだのさ。ふっふっふっ。","ENG":"And the Transfer Student helped her set them up. Hah hah hah.","TWN":"我這轉學生也幫了點忙呢，呵呵。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"마지막으로 볼지도 모르는 꽃잎, 다 함께 기억에 생생하게 새겨 놓자고 하는 그 아름다운 우정 이벤트......!","JPN":"最後になるかもしれない花びらを\\nみんなの記憶に鮮やかに刻む美しい友情のイベント……！","ENG":"A beautiful event for our friends, to make the sight of possibly our last flowers most memorable!","TWN":"在最後，你也許會想要看到櫻花飛舞在這場美麗的友情活動上……!"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"이름하야 플라워 익스플로전!","JPN":"名付けてフラワーエクスプロージョン！","ENG":"It's called the Flower Explosion!","TWN":"命名為——百花爆炸！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"전학생은 뜨거운 눈물을 흘리면서 계획에 동참한 것이었다......!","JPN":"転校生は熱い涙を流しながら計画に参加したのである……！","ENG":"The Transfer Student joined Irie's plan, shedding hot tears of strong emotions!","TWN":"我這轉學生是含著熱淚參加本次計畫呢……!"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"이 정도 양의 벚꽃을 모으려면 꽤 고생했겠는데? 전부 너희가 모은 거야?","JPN":"これだけの桜を集めるなんて、かなり苦労しただろ？　全部二人で集めたのか？","ENG":"It must have taken a long time to collect so many cherry blossoms. Did you collect them all by yourselves?","TWN":"要收集這麼多的櫻花應該很辛苦吧? 這都是妳收集的嗎?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"우리 집 전속 집사들이 밤새.","JPN":"我が家の専属執事たちが夜通しで。","ENG":"My family butlers did all night.","TWN":"是我家的管家們花了一個晚上做的！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"우와...... 마지막에 확 깬다, 야......","JPN":"うわぁ……最後の一言で冷めるぜ……","ENG":"Geez, that totally killed the mood girl.","TWN":"…覺得好像突然領悟了什麼，哈哈…"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ADMIN_SCHOOL_NULL_NULL","text":{"KOREA":"하하, 그래도 마지막인 만큼 멋진 사진이 나오겠네요.","JPN":"はは、でも最後なだけに素敵な写真が撮れそうですね。","ENG":"Hah hah, but this will make our last photo together look amazing.","TWN":"哈哈，但畢竟這是最後一次了，我們一定能拍出很好的照片。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"아, 잠깐! 야옹아! 어디 가는 거야!","JPN":"あっ、待て！　にゃんこちゃん！　どこ行くんだよ！","ENG":"Ah, wait! Kitty cat! Where are you going?","TWN":"啊，等一下！小貓貓！你去哪啊！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"꽃잎이 날리는 게 신기했나 보네. 금방 돌아올 테니까 서운해하지 마.","JPN":"花びらが舞うのが不思議だったみたいね。\\nすぐに戻ってくるから寂しがらないで。","ENG":"He went after the fluttering petals. Don't worry. He'll be back.","TWN":"看到花瓣在空中飛舞有一種神奇的感覺呢。我們很快就會回來的，不用這麼難過啦~"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"서, 서운하긴 누가 서운해한다고 그래?!","JPN":"さ、寂しいなんて思ってないからな！","ENG":"Wh-who says I'm worried?!","TWN":"妳說誰難過？我才不難過！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"이 사진으로 아이리 님의 귀여움을 남겨 둔단 말이지? 리미트 없이 어필할래!","JPN":"この写真でアイリ様の可愛さを残すってことね？　リミットなしでアピールするわ！","ENG":"You want to preserve Irie's cuteness in photos, huh? Knock yourself out!","TWN":"這張照片有把艾莉的可愛保存下來嗎？我好想要盡情發揮喔！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"앗, 아이리! 너 혼자 너무 들이대잖아!","JPN":"あっ、アイリ！　一人だけ顔を近づけすぎだ！","ENG":"Ah, Irie! You're taking up the whole frame!","TWN":"啊！艾莉！妳太愛出風頭了!"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"유진! 방정맞게 굴지 말고 촬영 때만큼은 얌전히 있도록.","JPN":"シロコ！　騒いでないで、撮影の時くらいは大人しくしてろ。","ENG":"Eujin! Stop making a fuss, at least during the photo shoot.","TWN":"劉珍！別那麼冒失，請像妳射擊的時候一樣安靜。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"윽, 왜 또 나한테만......","JPN":"うっ、なんでまた俺だけ……","ENG":"Sheesh, I didn't do anything wrong.","TWN":"唔，為什麼又是我..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"시엔 양, 혼자 바람 맞으면서 독백 그만 읊으시고 이쪽으로 오십시오.","JPN":"シエンさん、風に吹かれながら独白するのはやめて、こちらに来てください。","ENG":"Xien, please stop mumbling to yourself in the wind and come this way.","TWN":"西恩小姐，請不要一個人迎著風自言自語。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"후훗, 그렇게까지 내가 필요하다면 어쩔 수 없군.","JPN":"ふふっ、そんなに私が必要なら仕方ない。","ENG":"Hah hah. Okay, if you so desperately want me.","TWN":"哼哼，如果妳這麼需要我的話，真拿妳沒辦法。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"그런데 말이지 보스, 역시 이렇게 화사한 분위기는 내 하드보일드함이랑 역시 좀 안 맞는 느낌이───","JPN":"ところでボス、やはりこんな華やかな雰囲気は私のハードボイルドさと似合わない気が───","ENG":"By the way, Boss, maybe this setting is way too feminine for my tough, hard-boiled fictional character image—","TWN":"話說老闆，這種活潑的氛圍和我的冷硬派風格有點不搭———"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"GAP_BTYPE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>암호화 데이터 해독 완료.</color>","JPN":"<color=#ffd34c>暗号化データ解読完了。</color>","ENG":"<color=#ffd34c>Data decryption completed.</color>","TWN":"<color=#ffd34c>暗號化資料解讀完畢。</color>"},"stage":{"bg":"SPRING_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L22_1","type":"dialog","speaker":"GAP_BTYPE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>관리국 레거시 데이터베이스에 기록. 보안 4등급으로 설정.</color>","JPN":"<color=#ffd34c>管理局レガシーデータベースに記録。セキュリティ4等級に設定。</color>","ENG":"<color=#ffd34c>Saved in the Administration's Legacy database. Security level: 4.</color>","TWN":"<color=#ffd34c>管理局舊版資料庫記錄，機密等級設定為4。</color>"},"stage":{"bg":"SPRING_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......그래, 그랬었지.","JPN":"……ああ、そうだったな。","ENG":"... Yes, this is it.","TWN":"……喔，是這樣啊。"},"stage":{"bg":"SPRING_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이제야...... 기억이 조금 떠올랐어.","JPN":"やっと……記憶が少しよみがえった。","ENG":"Finally, I remembered.","TWN":"終於……浮現了一點記憶。"},"stage":{"bg":"SPRING_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래......","JPN":"そう……","ENG":"Yes...","TWN":"是嗎……"},"stage":{"bg":"SPRING_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"결국 타임캡슐은 전하지 못했군.","JPN":"結局タイムカプセルは渡せなかった。","ENG":"We didn't open the time capsule.","TWN":"結果還是沒能把這些傳到時光寶盒裡。"},"stage":{"bg":"SPRING_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 날, 위험을 무릅쓰고서라도 더 빨리 출발했다면......","JPN":"あの日、危険を冒してでも早く出発していれば……","ENG":"If we took off earlier that day, regardless of the risks,","TWN":"那天，就算要冒著一點危險，但如果能更早出發的話…"},"stage":{"bg":"SPRING_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그랬다면 그녀를 구할 수 있었을까......?","JPN":"彼女を救うことができただろうか……？","ENG":"would we have saved her?","TWN":"那樣就能把她救出來嗎？"},"stage":{"bg":"SPRING_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모든 것을...... 바꿀 수 있었을까......","JPN":"すべてを……変えることができただろうか……","ENG":"Would we have changed everything?","TWN":"一切就…有可能改變嗎..."},"stage":{"bg":"SPRING_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......옛날 일에 집착하는 걸 보니 나도 나이를 먹긴 하나 보군.","JPN":"……昔のことに執着するなんて、私も年を取ったようだ。","ENG":"... I must be getting old, dwelling on old days like this.","TWN":"…看到自己以前對工作那麼執著的樣子，現在看來我也已經上了年紀了。"},"stage":{"bg":"SPRING_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SPRING_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미안하다, 얘들아. 약속을 지키지 못해서.","JPN":"すまない、みんな。約束を守れなくて。","ENG":"I'm sorry, guys, that I didn't keep the promise.","TWN":"對不起，孩子們。我沒能遵守約定。"},"stage":{"bg":"SPRING_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이번에는......","JPN":"しかし今回は……","ENG":"But this time...","TWN":"但是，這次..."},"stage":{"bg":"SPRING_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이번에야말로 반드시......","JPN":"今回こそ必ず……","ENG":"I will. I promise.","TWN":"這次，一定要..."},"stage":{"bg":"SPRING_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};